import React, { useMemo, useState } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import { Lock, ShoppingCart, Truck } from 'lucide-react';
import SEO from '../components/SEO';
import toast from 'react-hot-toast';
import { useCart } from '../context/CartContext';
import LoadingSpinner from '../components/LoadingSpinner';
import EmptyState from '../components/EmptyState';
import CartItem from '../components/CartItem';
import { formatPKR } from '../utils/currency';

const FREE_SHIPPING_MIN = 50;
const SHIPPING_FLAT = 4.99;
const VAT_RATE = 0.2;

function round2(n) {
  return Math.round(Number(n) * 100) / 100;
}

/** VAT included in gross (UK-style): VAT portion = gross − net = gross × (r / (1+r)) */
function vatIncludedInGross(gross) {
  const g = Math.max(0, Number(gross) || 0);
  return round2(g - g / (1 + VAT_RATE));
}

const Cart = () => {
  const navigate = useNavigate();
  const {
    cart,
    cartState,
    loading: cartLoading,
    updateCartItem,
    removeFromCart,
    clearCart,
    applyCoupon,
    removeCoupon,
    getSubtotal
  } = useCart();
  const [couponCode, setCouponCode] = useState('');

  const totals = cartState.totals;

  const subtotal = getSubtotal();
  const discountAmount = useMemo(() => {
    if (totals && Number.isFinite(Number(totals.discountAmount))) {
      return Number(totals.discountAmount);
    }
    return Number(cartState.discountAmount) || 0;
  }, [totals, cartState.discountAmount]);

  const afterDiscount = useMemo(() => round2(Math.max(0, subtotal - discountAmount)), [subtotal, discountAmount]);

  const shipping = useMemo(() => {
    if (cart.length === 0) return 0;
    return afterDiscount >= FREE_SHIPPING_MIN ? 0 : SHIPPING_FLAT;
  }, [cart.length, afterDiscount]);

  const grandTotal = useMemo(() => round2(afterDiscount + shipping), [afterDiscount, shipping]);

  const taxIncluded = useMemo(() => vatIncludedInGross(grandTotal), [grandTotal]);

  const handleApplyCoupon = async () => {
    const code = couponCode.trim();
    if (!code) {
      toast.error('Enter a coupon code');
      return;
    }
    await applyCoupon(code);
  };

  const handleCheckout = () => {
    if (!cart.length) {
      toast.error('Your cart is empty');
      return;
    }
    navigate('/checkout');
  };

  return (
    <>
      <SEO
        noIndex
        title="Shopping cart"
        description="Review your Nova Shop basket, apply a coupon, and proceed to secure checkout."
        canonicalUrl="/cart"
      />
      <header className="page-header">
        <div className="container">
          <h1 className="page-header__title">Shopping cart</h1>
          <p className="page-header__subtitle">Review items, apply savings, then checkout securely.</p>
          <ol className="breadcrumb" aria-label="Breadcrumb">
            <li>
              <Link to="/">Home</Link>
            </li>
            <li>
              <Link to="/shop">Shop</Link>
            </li>
            <li className="active" aria-current="page">
              Cart
            </li>
          </ol>
        </div>
      </header>

      <main className="cart-page" id="main-content">
        <div className="container">
          <div className={`cart-layout ${cart.length === 0 ? 'cart-layout--empty' : ''}`}>
            <div className="cart-page__main">
              <div className="cart-page__head">
                <h2 className="cart-page__title">Your items</h2>
                {cart.length > 0 && (
                  <button type="button" className="cart-page__clear" onClick={() => clearCart()}>
                    Clear cart
                  </button>
                )}
              </div>

              <div className="cart-items">
                {cartLoading ? (
                  <div className="cart-loading">
                    <LoadingSpinner size="lg" label="Loading cart" />
                    <p className="cart-loading__note">Loading your cart…</p>
                  </div>
                ) : cart.length === 0 ? (
                  <EmptyState
                    className="cart-empty-state"
                    illustration={<ShoppingCart className="h-12 w-12 sm:h-14 sm:w-14" strokeWidth={1.25} aria-hidden />}
                    title="Your cart is empty"
                    message="Browse the shop and add products you love — free UK delivery on orders over £50."
                    actionLabel="Continue Shopping"
                    onAction={() => navigate('/shop')}
                  />
                ) : (
                  cart.map((line, idx) => {
                    const p = line.product || {};
                    const ref = p._id || line.product;
                    return (
                      <CartItem
                        key={String(ref)}
                        line={line}
                        animationDelay={`${idx * 0.08}s`}
                        onUpdateQuantity={(productRef, quantity) => updateCartItem(productRef, quantity)}
                        onRemove={(productRef) => removeFromCart(productRef)}
                      />
                    );
                  })
                )}
              </div>
            </div>

            {!cartLoading && cart.length > 0 ? (
              <aside className="cart-page__summary-wrap">
                <div className="cart-summary">
                  <h3>Order summary</h3>

                  <div className="coupon-group">
                    <input
                      type="text"
                      placeholder="COUPON CODE"
                      value={couponCode}
                      onChange={(e) => setCouponCode(e.target.value.toUpperCase())}
                      maxLength={32}
                      aria-label="Coupon code"
                    />
                    <button type="button" className="btn btn-gold btn-sm" onClick={handleApplyCoupon}>
                      Apply
                    </button>
                  </div>
                  {cartState.coupon && (
                    <p className="coupon-applied">
                      {cartState.coupon.code} applied
                      <button type="button" className="link-btn" onClick={() => removeCoupon()}>
                        Remove
                      </button>
                    </p>
                  )}

                  <div className="summary-row">
                    <span className="label">Subtotal</span>
                    <span className="value">£{round2(subtotal).toFixed(2)}</span>
                  </div>

                  {discountAmount > 0 ? (
                    <div className="summary-row">
                      <span className="label">Discount</span>
                      <span className="value summary-row__discount">−£{discountAmount.toFixed(2)}</span>
                    </div>
                  ) : null}

                  <div className="summary-row">
                    <span className="label">Shipping</span>
                    <span className="value">
                      {shipping === 0 ? (
                        <span className="cart-summary__free">Free</span>
                      ) : (
                        `£${shipping.toFixed(2)}`
                      )}
                    </span>
                  </div>
                  {afterDiscount < FREE_SHIPPING_MIN && cart.length > 0 ? (
                    <p className="cart-summary__ship-hint">
                      Add £{(FREE_SHIPPING_MIN - afterDiscount).toFixed(2)} more for free shipping (over £{FREE_SHIPPING_MIN}).
                    </p>
                  ) : null}

                  <div className="summary-row">
                    <span className="label">Tax (20% VAT)</span>
                    <span className="value">£{taxIncluded.toFixed(2)}</span>
                  </div>
                  <div className="summary-row summary-row--muted">
                    <span className="label">Included in total</span>
                    <span className="value">UK prices</span>
                  </div>

                  <div className="summary-row total">
                    <span className="label">Total</span>
                    <span className="value">£{grandTotal.toFixed(2)}</span>
                  </div>

                  <button
                    type="button"
                    className="btn btn-gold btn-full cart-summary__checkout"
                    onClick={handleCheckout}
                  >
                    <span className="cart-summary__checkout-label">PROCEED TO CHECKOUT</span>
                  </button>

                  <Link to="/shop" className="cart-summary__continue">
                    Continue Shopping
                  </Link>

                  <ul className="cart-trust-list" aria-label="Checkout benefits">
                    <li>
                      <Lock size={16} strokeWidth={1.75} aria-hidden />
                      Secure SSL checkout
                    </li>
                    <li>
                      <Truck size={16} strokeWidth={1.75} aria-hidden />
                      Free delivery on orders over £{FREE_SHIPPING_MIN}
                    </li>
                  </ul>
                  <p className="cart-summary__hint">
                    VAT is shown as included in your total (standard UK retail). Delivery options are confirmed at
                    checkout.
                  </p>
                </div>
              </aside>
            ) : null}
          </div>
        </div>
      </main>
    </>
  );
};

export default Cart;
